using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Models;

public class RecipeSubmission
{
    [Required(ErrorMessage = "Please enter a recipe title.")]
    [StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be between 3 and 100 characters.")]
    public string Title { get; set; } = "";

    [Required(ErrorMessage = "Please select a category.")]
    public string Category { get; set; } = "";

    [Required(ErrorMessage = "Please enter at least one ingredient.")]
    [MinLength(3, ErrorMessage = "Please enter at least one ingredient.")]
    public string Ingredients { get; set; } = "";

    [Required(ErrorMessage = "Please enter the preparation steps.")]
    [MinLength(10, ErrorMessage = "Please provide more detailed steps.")]
    public string Steps { get; set; } = "";
}

@page "/recipes"
@page "/recipes/{Category}"

<PageTitle>Recipes - @(Category ?? "All Categories")</PageTitle>

<h1>@GetCategoryTitle()</h1>

@if (Category is null)
{
    <p>Select a category from the homepage or use the links below:</p>
    <ul>
        <li><a href="recipes/appetizers">Appetizers</a></li>
        <li><a href="recipes/main-courses">Main Courses</a></li>
        <li><a href="recipes/desserts">Desserts</a></li>
        <li><a href="recipes/beverages">Beverages</a></li>
        <li><a href="recipes/quick-and-easy">Quick &amp; Easy</a></li>
        <li><a href="recipes/vegetarian">Vegetarian</a></li>
    </ul>
}
else
{
    var recipes = GetRecipesForCategory();
    @if (recipes.Any())
    {
        <div class="row">
            @foreach (var recipe in recipes)
            {
                <div class="col-md-6 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text">@recipe.Description</p>
                            <a href="recipes/@Category/@recipe.Slug" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
    else
    {
        <p>No recipes found in this category yet. <a href="submit">Submit one!</a></p>
    }
}

@code {
    [Parameter]
    public string? Category { get; set; }

    private string GetCategoryTitle() => Category switch
    {
        "appetizers" => "🥗 Appetizers",
        "main-courses" => "🍝 Main Courses",
        "desserts" => "🍰 Desserts",
        "beverages" => "🥤 Beverages",
        "quick-and-easy" => "🥪 Quick & Easy",
        "vegetarian" => "🌱 Vegetarian",
        _ => "Browse Recipes"
    };

    private List<RecipeSummary> GetRecipesForCategory() => Category switch
    {
        "appetizers" => new()
        {
            new("Bruschetta", "bruschetta", "Classic Italian toasted bread with tomatoes and basil."),
            new("Spinach Dip", "spinach-dip", "Creamy spinach and artichoke dip served with crackers.")
        },
        "main-courses" => new()
        {
            new("Spaghetti Carbonara", "spaghetti-carbonara", "Rich and creamy Italian pasta with pancetta and egg."),
            new("Grilled Chicken", "grilled-chicken", "Juicy herb-marinated chicken grilled to perfection.")
        },
        "desserts" => new()
        {
            new("Chocolate Lava Cake", "chocolate-lava-cake", "Decadent molten chocolate cake with a gooey center."),
            new("Tiramisu", "tiramisu", "Classic Italian coffee-flavored layered dessert.")
        },
        "beverages" => new()
        {
            new("Mango Smoothie", "mango-smoothie", "Tropical mango blended with yogurt and honey."),
            new("Iced Matcha Latte", "iced-matcha-latte", "Refreshing green tea latte over ice.")
        },
        "quick-and-easy" => new()
        {
            new("Avocado Toast", "avocado-toast", "Simple smashed avocado on crispy sourdough."),
            new("Caprese Salad", "caprese-salad", "Fresh mozzarella, tomatoes, and basil with balsamic glaze.")
        },
        "vegetarian" => new()
        {
            new("Vegetable Stir Fry", "vegetable-stir-fry", "Colorful veggies tossed in a savory sauce."),
            new("Mushroom Risotto", "mushroom-risotto", "Creamy Arborio rice with earthy mushrooms and Parmesan.")
        },
        _ => new()
    };

    private record RecipeSummary(string Title, string Slug, string Description);
}

@page "/recipes/{Category}/{Slug}"

<PageTitle>@(GetRecipe()?.Title ?? "Recipe Not Found") - RecipeShare</PageTitle>

@{
    var recipe = GetRecipe();
}

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe. <a href="recipes">Browse all recipes</a>.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="recipes">Recipes</a></li>
            <li class="breadcrumb-item"><a href="recipes/@Category">@GetCategoryName()</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="text-muted">@recipe.Description</p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>

    <hr />
    <h4>Rate this Recipe</h4>
    <StarRating RecipeSlug="@Slug" @rendermode="InteractiveServer" />
}

@code {
